import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List


def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Early exit for trivial cases
    if not dsts:
        return bc_topology
    if num_partitions == 0:
        return bc_topology

    # Compute shortest paths with cost-aware multicast tree construction
    all_paths = {}

    # Sort destinations by path cost to prioritize efficient routing
    dst_costs = {}
    for dst in dsts:
        try:
            cost = nx.dijkstra_path_length(h, src, dst, weight="cost")
            dst_costs[dst] = cost
        except nx.NetworkXNoPath:
            dst_costs[dst] = float('inf')

    # Process destinations in order of increasing cost
    sorted_dsts = sorted(dsts, key=lambda d: dst_costs[d])

    for dst in sorted_dsts:
        try:
            path = nx.dijkstra_path(h, src, dst, weight="cost")
            all_paths[dst] = path
        except nx.NetworkXNoPath:
            # Fallback: try direct connection or empty path
            if h.has_edge(src, dst):
                all_paths[dst] = [src, dst]
            else:
                all_paths[dst] = []

    # Strategy: Use path diversity to distribute load across network
    # Partition 0: shortest path
    # Other partitions: alternative paths with modified costs to balance load

    for dst in dsts:
        if dst not in all_paths or not all_paths[dst]:
            # Handle edge case: no path found, try direct edge
            if h.has_edge(src, dst):
                for partition_id in range(num_partitions):
                    bc_topology.append_dst_partition_path(dst, partition_id, [src, dst, G[src][dst]])
            continue

        main_path = all_paths[dst]

        # Skip destinations with very short paths (no alternatives possible)
        if len(main_path) < 2:
            continue

        # Partition 0: use the shortest path
        for i in range(len(main_path) - 1):
            s, t = main_path[i], main_path[i + 1]
            bc_topology.append_dst_partition_path(dst, 0, [s, t, G[s][t]])

        # For other partitions, find alternative paths to balance load
        for partition_id in range(1, num_partitions):
            # Create modified graph with increased costs on main path edges
            # This encourages finding alternative routes
            h_modified = h.copy()

            # Penalize main path edges proportional to partition id
            penalty_factor = 1 + 0.2 * partition_id
            for i in range(len(main_path) - 1):
                s, t = main_path[i], main_path[i + 1]
                if h_modified.has_edge(s, t):
                    h_modified[s][t]["cost"] *= penalty_factor

            try:
                # Find alternative path with modified costs
                alt_path = nx.dijkstra_path(h_modified, src, dst, weight="cost")
